import React from 'react';

const ContactoPage = () => {
  const leftImage = {
    src: '/media/contactoPage/UCBA.png',
    alt: 'Entrada UCB',
    link: 'https://www.ucb.edu.bo/',
  };

  const rightColumnImages = [
    {
      main: {
        src: '/media/contactoPage/SISE.png',
        alt: 'Logo SIS',
        link: 'https://www.ucb.edu.bo/contacto',
      },
      qr: {
        src: '/media/contactoPage/qr.png',
        alt: 'QR SIS',
        link: 'https://www.ucb.edu.bo/contacto/qr',
      },
    },
    {
      main: {
        src: '/media/contactoPage/ADM - H.png',
        alt: 'Logo ADM',
        link: 'https://www.ucb.edu.bo/nosotros',
      },
      qr: {
        src: '/media/contactoPage/qr.png',
        alt: 'QR ADM',
        link: 'https://www.ucb.edu.bo/nosotros/qr',
      },
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>

        <div style={styles.mainRow}>
          {/* Imagen izquierda grande, sin cambiar tamaño */}
          <a href={leftImage.link} target="_blank" rel="noopener noreferrer" style={styles.leftImageLink}>
            <img src={leftImage.src} alt={leftImage.alt} style={styles.leftImage} />
          </a>

          {/* Columna derecha: 2 bloques con imagen principal arriba y QR abajo */}
          {rightColumnImages.map(({ main, qr }, idx) => (
            <div key={idx} style={styles.rightColumn}>
              <a href={main.link} target="_blank" rel="noopener noreferrer" style={styles.rightImageLink}>
                <img src={main.src} alt={main.alt} style={styles.rightImage} />
              </a>
              <a href={qr.link} target="_blank" rel="noopener noreferrer" style={styles.qrLink}>
                <img src={qr.src} alt={qr.alt} style={styles.qrImage} />
              </a>
            </div>
          ))}
        </div>
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  container: {
    maxWidth: 960,
    margin: '0 auto',
    padding: '0 1rem',
    color: '#052018',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '2rem',
    textAlign: 'center',
    color: '#052018',
  },

  mainRow: {
    display: 'flex',
    gap: '1.5rem',
    alignItems: 'flex-start',
  },

  leftImageLink: {
    flex: '0 0 auto',
    maxWidth: 320,
  },
  leftImage: {
    width: '320px', // Mantener tamaño original (o el que usabas)
    height: 'auto',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },

  rightColumn: {
    display: 'flex',
    flexDirection: 'column',
    gap: '1.5rem',
    flex: '0 0 auto',
    maxWidth: 160, // Mitad del ancho de la imagen izquierda para dos imágenes apiladas
  },

  rightImageLink: {
    display: 'block',
  },
  rightImage: {
    width: '160px', // Igual ancho que contenedor para que se ajuste bien
    height: 'auto',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },

  qrLink: {
    display: 'block',
  },
  qrImage: {
    width: '160px', // Igual ancho que la imagen principal de la columna
    height: 'auto',
    borderRadius: 12,
    boxShadow: '0 1px 8px rgba(0,0,0,0.1)',
    display: 'block',
  },
};

export default ContactoPage;
